mapper.insert:
INSERT INTO feed
    SET   location = #{location}
        , contents = #{contents}
        ,  user_id = #{signedUserId}

mapper.select:
SELECT f.id, f.contents, f.location, f.created_at , u.id AS writerUserId , u.uid AS writerUid , u.nm AS writerNickName , u.pic AS writerPic FROM feed f JOIN user u ON u.id = f.user_id
WHERE f.user_id = #{profileUserId}
ORDER BY f.id DESC LIMIT #{startIdx}, #{size}

SELECT pic
FROM feed_pic
WHERE feed_id = #{feedId}
